  ('pukao-7fec267e-moex-00154', 'pukao-7fec267e', 'pukao-7fec267e-moex-113-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '某政黨是因為有些國會議員政策理念相同，先在國會組成次級團體，之後才正式成立的政黨。該 黨是屬於下列何種類型的政黨？', '["內造政黨", "群眾型政黨", "掮客型政黨", "個人式政黨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:14+00:00", "source_pdf_sha1": "e33ed465b68f", "answer_pdf_sha1": "7b2d6d567598", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00155', 'pukao-7fec267e', 'pukao-7fec267e-moex-113-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '政府部門為了避免決策或資源分配時過度偏袒特定的族群或團體，應從人口或地域等多元面向來考慮行政 機關的人力結構，以求充分反映各個階層的利益或意見。下列那一個概念與此一主張最為相近？', '["審議式民主", "代表性官僚", "代議式民主", "行政中立化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:14+00:00", "source_pdf_sha1": "911a7b7a5265", "answer_pdf_sha1": "4139af4fbb5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "401", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
